define(["core/notification"],function(c){return{init:function(a,n){document.addEventListener("click",function(e){var t=e.target.closest('[data-action="copy-widget"]');if(t){var i=t.getAttribute("data-code");var o=function(e){var t=document.createElement("textarea");t.value=e;t.style.top="0";t.style.left="0";t.style.position="fixed";document.body.appendChild(t);t.focus();t.select();try{var i=document.execCommand("copy");if(i){c.addNotification({message:a,type:"success"})}else{c.addNotification({message:n,type:"error"})}}catch(e){c.addNotification({message:n,type:"error"})}document.body.removeChild(t)};if(!navigator.clipboard){o(i);return}navigator.clipboard.writeText(i).then(function(){c.addNotification({message:a,type:"success"});return true}).catch(function(){o(i);return false})}})}}});